"use strict";(self.webpackChunkwoocommerce_ebay_connector=self.webpackChunkwoocommerce_ebay_connector||[]).push([[504],{567(e,t,a){a.r(t),a.d(t,{comp:()=>b,data:()=>y});var n=a(641);const o=a.p+"assets/img/ebay.da266ec6.webp",s=a.p+"assets/img/create-account.5a210d05.webp",r=a.p+"assets/img/productionaccount.8e5a2067.webp",i=a.p+"assets/img/application-keys.552442c0.webp",c=a.p+"assets/img/enviroment.728c8a7c.webp",l=a.p+"assets/img/agreement.a4d69750.webp",d=a.p+"assets/img/sandbox-account.8b7cf190.webp",h=a.p+"assets/img/production.6eb79565.webp",p=a.p+"assets/img/login.a1201b13.webp",g=a.p+"assets/img/add-account.41da6b0d.webp",u=a.p+"assets/img/account-add.90e636bb.webp",m={},b=(0,a(6262).A)(m,[["render",function(e,t){return(0,n.uX)(),(0,n.CE)("div",null,[...t[0]||(t[0]=[(0,n.Fv)('<h1 id="ebay-account-setup-–-woocommerce-ebay-connector" tabindex="-1"><a class="header-anchor" href="#ebay-account-setup-–-woocommerce-ebay-connector"><span>eBay Account Setup – WooCommerce eBay Connector</span></a></h1><p>This section allows the admin to obtain eBay API credentials and connect their eBay seller account with the WooCommerce store.</p><hr><h2 id="how-to-get-ebay-api-credentials" tabindex="-1"><a class="header-anchor" href="#how-to-get-ebay-api-credentials"><span>How to Get eBay API Credentials</span></a></h2><p>To perform the eBay Connector configuration, the admin must obtain the eBay developer keys (App Id, Cert Id, Dev Id, User ID, and Auth Token) from the <a href="https://developer.ebay.com/" target="_blank" rel="noopener noreferrer">eBay Developer Portal</a>.</p><h3 id="follow-these-steps-to-get-credentials" tabindex="-1"><a class="header-anchor" href="#follow-these-steps-to-get-credentials"><span>Follow these steps to get credentials</span></a></h3><ul><li><strong>Create Developer Account:</strong> The admin can navigate to <a href="https://developer.ebay.com/" target="_blank" rel="noopener noreferrer">developer.ebay.com</a> and click on the <strong>Sign-in/Join</strong> link to create a new account.</li></ul><p><a class="doc-image-link" href="./assets/ebay.webp"><img src="'+o+'" alt="eBay Developer Portal"></a></p><p><a class="doc-image-link" href="./assets/create-account.webp"><img src="'+s+'" alt="Create eBay Developer Account"></a></p><h3 id="step-2-create-an-application" tabindex="-1"><a class="header-anchor" href="#step-2-create-an-application"><span>Step 2: Create an Application</span></a></h3><ul><li>The admin can create a new application by entering the <strong>App Name</strong>.</li><li>Choose the appropriate <strong>Environment</strong> (Sandbox or Production) to generate the <strong>Key Set</strong>.</li></ul><blockquote><p>[!NOTE] The application name will not be saved until the keys are generated.</p></blockquote><h3 id="step-3-generate-keys" tabindex="-1"><a class="header-anchor" href="#step-3-generate-keys"><span>Step 3: Generate Keys</span></a></h3><ul><li>The admin must enter the application name and select the environment to generate the key set.</li><li>For actual business operations, it is recommended to configure the module with a <strong>Production (Live)</strong> eBay account.</li></ul><p><a class="doc-image-link" href="./assets/productionaccount.webp"><img src="'+r+'" alt="eBay Production Keys"></a></p><h3 id="step-4-generate-user-token" tabindex="-1"><a class="header-anchor" href="#step-4-generate-user-token"><span>Step 4: Generate User Token</span></a></h3><ul><li>The admin navigates to the <strong>Application Keys</strong> page.</li><li>In the <strong>App ID</strong> row of the Production keyset, click on <strong>User Tokens</strong> to access the tokens page.</li></ul><p><a class="doc-image-link" href="./assets/application-keys.webp"><img src="'+i+'" alt="eBay User Tokens"></a></p><blockquote><p>[!IMPORTANT] The eBay Sandbox account is for testing purposes only. For real product exports and order synchronization, a <strong>Production (Live)</strong> account is required.</p></blockquote><ul><li>Click on the <strong>Sign in to Production</strong> button to authorize the account.</li></ul><p><a class="doc-image-link" href="./assets/enviroment.webp"><img src="'+c+'" alt="Sign in to Production"></a></p><ul><li>After signing in, click the <strong>Agree</strong> button to provide authorization.</li></ul><p><a class="doc-image-link" href="./assets/agreement.webp"><img src="'+l+'" alt="eBay User Agreement"></a></p><hr><h2 id="sandbox-account-setup" tabindex="-1"><a class="header-anchor" href="#sandbox-account-setup"><span>Sandbox Account Setup</span></a></h2><p>To test the eBay Connector features without affecting live listings, the admin can create a Sandbox account:</p><ul><li>Click on the <strong>Register a new Sandbox user</strong> link.</li><li>The admin will be redirected to the <strong>Register for Sandbox</strong> page to create test users.</li></ul><p><a class="doc-image-link" href="./assets/sandbox-account.webp"><img src="'+d+'" alt="eBay Sandbox Account"></a></p><h3 id="steps-to-complete-registration" tabindex="-1"><a class="header-anchor" href="#steps-to-complete-registration"><span>Steps to Complete Registration</span></a></h3><ul><li>Fill in the required information in the registration form.</li><li>Review and accept the <strong>User Agreement</strong> and <strong>API License Agreement</strong>.</li><li>Click the <strong>Register</strong> button to create the test user.</li><li>The admin can then proceed by entering the Sandbox <strong>Username</strong> and <strong>Password</strong>.</li></ul><p><a class="doc-image-link" href="./assets/production.webp"><img src="'+h+'" alt="Sandbox Account Note"></a></p><p><a class="doc-image-link" href="./assets/login.webp"><img src="'+p+'" alt="eBay Sandbox Login"></a></p><hr><h2 id="add-ebay-account-in-connector-module" tabindex="-1"><a class="header-anchor" href="#add-ebay-account-in-connector-module"><span>Add eBay Account in Connector Module</span></a></h2><p>Once the API credentials are obtained, the admin can configure the eBay account within the module:</p><p><a class="doc-image-link" href="./assets/add-account.webp"><img src="'+g+'" alt="Add eBay Account"></a></p><h3 id="workflow-to-add-account" tabindex="-1"><a class="header-anchor" href="#workflow-to-add-account"><span>Workflow to Add Account</span></a></h3><ul><li>The admin navigates to <strong>WC eBay Connector</strong> in the WordPress admin panel.</li><li>Click on the <strong>Add New</strong> button to initiate the account connection.</li></ul><p><a class="doc-image-link" href="./assets/account-add.webp"><img src="'+u+'" alt="Add New eBay Account"></a></p><h3 id="configuration-fields" tabindex="-1"><a class="header-anchor" href="#configuration-fields"><span>Configuration Fields</span></a></h3><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Store Name</strong></td><td>Enter the store name for internal identification.</td></tr><tr><td><strong>Select Global Site</strong></td><td>Choose the eBay site (e.g., US, UK, India) to which the account belongs.</td></tr><tr><td><strong>eBay User ID</strong></td><td>Enter the eBay seller user ID.</td></tr><tr><td><strong>eBay Application Token</strong></td><td>This will be fetched automatically after connection.</td></tr><tr><td><strong>Developer ID</strong></td><td>Paste the Dev ID from the eBay Developer Portal.</td></tr><tr><td><strong>Application ID</strong></td><td>Paste the App ID (Client ID).</td></tr><tr><td><strong>Certification ID</strong></td><td>Paste the Cert ID (Client Secret).</td></tr><tr><td><strong>Account Type</strong></td><td>Select either <strong>Sandbox</strong> or <strong>Production</strong>.</td></tr></tbody></table><ul><li>Click the <strong>Save Account</strong> button to complete the process.</li></ul><hr><h2 id="ebay-account-list" tabindex="-1"><a class="header-anchor" href="#ebay-account-list"><span>eBay Account List</span></a></h2><p>This section allows the admin to manage multiple connected eBay accounts:</p><p><a class="doc-image-link" href="./assets/add-account.webp"><img src="'+g+'" alt="eBay Account List"></a></p><h3 id="available-actions" tabindex="-1"><a class="header-anchor" href="#available-actions"><span>Available Actions</span></a></h3><ul><li><strong>Edit:</strong> The admin can modify account details by clicking the <strong>Edit</strong> link.</li><li><strong>Delete:</strong> Remove an account by selecting <strong>Delete</strong> from the bulk actions or the individual entry.</li><li><strong>View Accounts:</strong> Monitor the status and details of all integrated eBay accounts.</li></ul>',48)])])}]]),y=JSON.parse('{"path":"/documentation/ebay-account-setup.html","title":"eBay Account Setup – WooCommerce eBay Connector","lang":"en-US","frontmatter":{"prev":"/documentation/installation.html","next":"/documentation/configuration.html"},"git":{"contributors":[{"name":"shakir.hussain","username":"","email":"shakir.hussain421@webkul.in","commits":2},{"name":"aadesh","username":"","email":"aadesh.8209@webkul.in","commits":2}],"changelog":[{"hash":"86ec3d42e91345957915d7d678cf29733245262d","time":1774624521000,"email":"shakir.hussain421@webkul.in","author":"shakir.hussain","message":"updated blog contant"},{"hash":"2d5c39163a248635a79c60d8508c0716b0a11c03","time":1772114569000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"add export product"},{"hash":"a3379ad1acde7722f52940c853addb733657393e","time":1771942912000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"update images"},{"hash":"277c5a1bdc13e06551e102ee26c728b6b048e50b","time":1771481506000,"email":"shakir.hussain421@webkul.in","author":"shakir.hussain","message":"updated ebay blog and move to dev"}]},"filePathRelative":"documentation/ebay-account-setup.md"}')}}]);